#include <bits/stdc++.h>
using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int N;
    cin >> N;
    vector<int> b(N - 1);
    for (int i = 0; i < N - 1; i++) {
        cin >> b[i];
    }

    // Try a[0] = start_val for start_val from 1..N
    // Once a[0] is fixed, all a[i] are determined:
    // a[1] = b[0] - a[0]
    // a[2] = b[1] - a[1]
    // etc.
    // We need a permutation of 1..N, all values in [1,N].

    vector<int> best_a;

    for (int start = 1; start <= N; start++) {
        vector<int> a(N);
        a[0] = start;
        bool ok = true;
        vector<bool> used(N + 1, false);
        used[a[0]] = true;
        for (int i = 1; i < N; i++) {
            a[i] = b[i - 1] - a[i - 1];
            if (a[i] < 1 || a[i] > N || used[a[i]]) {
                ok = false;
                break;
            }
            used[a[i]] = true;
        }
        if (!ok) continue;

        // If first valid found, it's lexicographically smallest because
        // we try a[0] from 1 upward.
        // Print and return.
        for (int i = 0; i < N; i++) {
            if (i > 0) cout << ' ';
            cout << a[i];
        }
        cout << '\n';
        return 0;
    }

    // Should never reach here because solution guaranteed.
    return 0;
}
